placement_interface:
## Two new module-private TUs: `src/resources/resources_cap.{h,c}` (the token + authority + ledger) and `src/resources/resources_place.{h,c}` (the vtable + backing). `include/anoptic_resources.h` handle semantics do not change.

### 1. The token (`resources_cap.h`)

```c
// The capability. 16 bytes, by value. Zero is the null capability; every consumer refuses it.
// Constructed ONLY by res_cap_mint. `charge` is the interned ledger cell this token will bill:
// a capability that cannot be charged cannot be minted, so an unattributed byte is unrepresentable.
typedef struct res_cap {
    uint32_t owner;          // lifetime domain slot 1..RES_DOMAIN_MAX; 0 = null
    uint32_t owner_gen;      // domain generation: a stale token refuses at every boundary
    uint16_t axes;           // kind:5 | role:3 | op:4 | dest:4  (RES_CAP_KIND(c) etc.)
    uint8_t  disposition;    // res_disposition
    uint8_t  lifetime_kind;  // ano_res_lifetime_kind, denormalized so plan() is pure
    uint32_t charge;         // interned ledger cell id; 0 = the overflow cell (counted, never silent)
} res_cap;
static_assert(sizeof(res_cap) == 16, "capability is two words");

typedef struct res_cap_req {
    ano_res_lifetime lifetime;
    res_kind         kind;
    res_role         role;
    res_operation    operation;
    res_destination  destination;   // + RES_DEST_CHUNK, RES_DEST_STRIPE (new)
    res_disposition  disposition;   // RETAIN for an ordinary allocation
    size_t           alignment;     // 0 = ANO_CACHE_LINE
} res_cap_req;

// Mint refuses (null cap + one ERROR) when: the domain is dead or its generation is stale;
// (kind,role,destination) is not in the authority's legal table; the disposition is illegal for
// this lifetime pair; or NO arena the active placement offers for this tuple can deliver
// req->alignment. Illegal placement is therefore unrepresentable, not merely rejected late.
res_cap res_cap_mint(const res_cap_req *req);
bool    res_cap_valid(res_cap c);
size_t  res_cap_alignment(res_cap c);

// The ONLY way a capability changes lifetime domain. Refused unless the authority permits
// {from.lifetime_kind -> to.kind, disposition}. The result names the DESTINATION domain and a
// DISTINCT ledger cell, so a promotion's bytes can never be billed to the source.
res_cap res_cap_transition(res_cap from, ano_res_lifetime to, res_disposition d);
```

The authority is one static table, `res_cap_legal[RES_ROLE_COUNT][RES_DEST_COUNT]` plus a
`res_cap_disposition[LIFETIME_COUNT][LIFETIME_COUNT]` matrix. `res_disposition_allowed` becomes a
**pure** predicate that mutates no counters (fixing the "counters count questions" bug); the
counters move to `res_owned_move`, which is the only thing that actually moves bytes.

### 2. The site and the backing (`resources_place.h`)

```c
typedef enum res_arena_id {
    RES_ARENA_METADATA = 0,   // registry shard, names, dep records, placement meta, control records
    RES_ARENA_PAYLOAD_SMALL, RES_ARENA_PAYLOAD_BULK,
    RES_ARENA_CHUNK,          // fixed RMOS_CHUNK_MAX blocks (ano_mem_pool)
    RES_ARENA_STRIPE,         // cache-striped SoA planes (ano_mem_stripe)
    RES_ARENA_STAGING,        // monotonic parse/decode/compile staging
    RES_ARENA_TRANSFER,       // blocks that may leave the manager
    RES_ARENA_COUNT
} res_arena_id;

typedef enum res_backing_kind {
    RES_BACK_NONE = 0, RES_BACK_MULTIPOOL, RES_BACK_POOL,
    RES_BACK_MONOTONIC, RES_BACK_STRIPE, RES_BACK_HEAP
} res_backing_kind;

#define RES_SITE_TRANSFERABLE 0x01u  // may leave the manager with no copy, no interior free
#define RES_SITE_DIRECT_LAND  0x02u  // IO/decoder may write straight into this block
#define RES_SITE_WINKABLE     0x04u  // reclaimed en masse by wink(); free(WINK) is accounting-only

typedef struct res_site {
    uint16_t arena;      // res_arena_id
    uint8_t  backing;    // res_backing_kind
    uint8_t  flags;
    void    *allocator;  // the concrete ano_mem_multipool*/ano_mem_pool*/ano_mem_monotonic*/
                         // ano_mem_stripe*/mi_heap_t* this block came from
    size_t   serving;    // what the arena WILL charge. Authoritative. serving_size() is DELETED.
    size_t   alignment;  // what the arena WILL deliver. plan() refuses rather than under-deliver.
} res_site;

// One live ownership domain's backing. A model may leave `root` NULL when its hierarchy is not
// lifetime-rooted (B, D): then wink() is a bookkeeping no-op and free(RETAIL) does the real work.
typedef struct res_backing {
    mi_heap_t *root;                     // wink-out root; every arena's parent chain ends here
    mi_heap_t *transfer_root;            // OUTLIVES root while transfers are outstanding
    void      *arena[RES_ARENA_COUNT];
    uint8_t    kindof[RES_ARENA_COUNT];
    void      *model_state;              // B: per-kind table. D: per-role table. E: both.
    ano_res_lifetime lifetime;
    size_t     transfers_outstanding;    // named, charged, auditable — not a hidden refcount
} res_backing;

typedef enum res_free_mode { RES_FREE_RETAIL = 0, RES_FREE_WINK = 1 } res_free_mode;

// THE CONTEST SEAM. Six functions. One TU per contestant.
typedef struct res_placement {
    const char *name;                     // "global-pool" | "scoped-pool" (A.4 bullet 1 scaffolds)
                                          // Stage B: "model-a" .. "model-e"
    int   (*open) (const struct res_placement *, ano_res_lifetime, res_backing *out);
    void  (*wink) (const struct res_placement *, res_backing *);
    int   (*plan) (const struct res_placement *, const res_backing *,
                   res_cap cap, size_t size, res_site *out);          // PURE. routes, allocates nothing.
    void *(*alloc)(const struct res_placement *, res_backing *, const res_site *, size_t);
    void  (*free) (const struct res_placement *, res_backing *, const res_site *,
                   void *p, size_t size, res_free_mode);
    ano_mem_stats (*arena_stats)(const struct res_placement *, const res_backing *, res_arena_id);
} res_placement;

const res_placement *res_placement_active(void);   // selected once at res_registry_init
const char          *res_placement_name(void);     // logged at INFO, reported in ano_res_stats
```

`ANO_RES_PLACEMENT=global|scoped` (default `scoped`), read once, logged
`resources: placement scaffold 'scoped-pool'`. This **restores** the truthful scaffold naming the
working tree deleted (verified gone: `git grep ANO_RES_PLACEMENT -- src include tests` is empty).
Stage B registers five more vtables and touches nothing else.

### 3. The allocation surface (`resources_internal.h`) — every verb takes a capability

```c
typedef struct res_owned_block {
    void    *data;
    size_t   size;
    res_site site;      // authoritative; replaces `bool pooled` AND `bool transfer_compatible`
    res_cap  cap;       // who authorized this block, and which cell it is billed to
} res_owned_block;

int  res_owned_plan  (res_cap, size_t size, res_site *out);          // route only
int  res_owned_alloc (res_cap, size_t size, res_owned_block *out);
int  res_owned_stage (res_cap, size_t hint,  res_owned_block *out);  // RES_ARENA_STAGING
int  res_owned_commit(res_owned_block *staged, res_cap home, res_owned_block *out);
     // 0 copies when the staged site == the planned home site (direct landing); otherwise
     // exactly ONE copy, charged to home's cell. The hint-lie spill path lives here.
int  res_owned_move  (res_owned_block *from, res_cap to, res_owned_block *out);
     // THE ONLY cross-domain mover. `to` MUST be res_cap_transition(from->cap, ...).
     // Zero-copy iff both sites are RES_SITE_TRANSFERABLE and share a reclaim root; otherwise
     // one charged copy. Bills promotions/duplications/copies/bytes_copied to `to`'s cell.
void res_owned_free  (res_owned_block *, res_free_mode);
void res_account_copy(res_cap, size_t bytes);            // still requires a cap
```

`transfer_compatible` is **deleted from the caller's vocabulary**. It was a size threshold
duplicated at three call sites (`resources_registry.c:798`, `res_graphics.c:458`, `:681`) masquerading
as a placement decision. It is now `res_site.flags & RES_SITE_TRANSFERABLE` — an **output** of the
model's `plan()`. A Model D/E that gives consumable kinds a transfer arena gets zero-copy at *any*
size; a Model A that pools everything pays the copy and the bench **sees** it. `RES_POOL_MAX` stops
being a global constant and becomes each model's `ano_mem_multipool_cfg.max_block`.

### 4. Destination-aware reads (kills the mandatory staging copy)

`ano_res_get` today does `res_read_all(NULL,…)` → default-heap buffer → `res_owned_alloc` →
`memcpy` → `mi_free`. That staging buffer is invisible to every counter. Replace with an EOF-truth
sink so the home block, the staging arena, or an exact pack-sized block are all expressible behind
one read loop:

```c
typedef struct res_sink {
    void *ctx;
    void *(*reserve)(void *ctx, size_t hint, size_t *out_cap);  // may hand back the HOME block
    void *(*grow)   (void *ctx, size_t need, size_t *out_cap);  // hint lied: spill, one charged copy
    void  (*commit) (void *ctx, size_t final_size);
} res_sink;
int res_read_sink(const res_sink *, const char *abs, size_t *out_size);
```
`res_read_all` becomes a thin wrapper (its EOF-truth loop is preserved verbatim — `*got == 0` is the
ONLY EOF signal). The spill is billed as `hint_mismatch_copies`, which is the honest measurement of
the 9P/SMB floor rather than a wish that hints be true.

five_model_proof:
Every model is ONE TU exporting one `const res_placement`. None of them may touch
`include/anoptic_resources.h`, `anores_t`, `ano_res_get/bytes/release/unload`, `res_graphics.c`,
the renderer, config, keybindings, world, audio, or script. Proof by construction: the *only* thing a
model implements is the six-function vtable, and the only thing the registry calls is
`res_owned_plan/alloc/stage/commit/move/free` — all of which take a `res_cap` and none of which name
an allocator.

The trick that makes all five expressible with one `res_backing`: **`backing.root` may be NULL**, and
**`free()` takes a `res_free_mode`**. A model whose hierarchy is lifetime-rooted sets
`RES_SITE_WINKABLE`, no-ops `free(WINK)`, and destroys one heap. A model whose hierarchy outlives
lifetime domains leaves `root == NULL`, does real retail work in `free(RETAIL)` *and* `free(WINK)`, and
no-ops `wink()`. The registry's order is invariant — retire rows → free each block → wink — so both
shapes are correct without a special case anywhere in `resources_registry.c`.

### Model A — one complete multipool  (`place_model_a.c`)
```c
static struct a_state { mi_heap_t *root; ano_mem_multipool *mp; mi_heap_t *transfer; } g_a;

static int a_open(const res_placement *s, ano_res_lifetime lt, res_backing *b) {
    (void)s;
    if (!g_a.root) {                                   // first domain builds THE root; there is one.
        g_a.root = mi_heap_new();
        g_a.mp   = ano_mem_multipool_make(ano_mem_parent_heap(g_a.root),
                     &(ano_mem_multipool_cfg){ .min_block = ANO_CACHE_LINE, .max_block = 4u<<20 });
        g_a.transfer = mi_heap_new();                  // declared primitive, same root ownership, charged
    }
    *b = (res_backing){ .root = NULL,                  // NO per-lifetime root: A cannot wink out a subset
                        .transfer_root = g_a.transfer, .model_state = &g_a, .lifetime = lt };
    for (int i = 0; i < RES_ARENA_COUNT; i++) {        // every arena IS the one multipool
        b->arena[i] = g_a.mp; b->kindof[i] = RES_BACK_MULTIPOOL;
    }
    b->arena[RES_ARENA_TRANSFER] = g_a.transfer; b->kindof[RES_ARENA_TRANSFER] = RES_BACK_HEAP;
    return 0;
}
static int a_plan(const res_placement *s, const res_backing *b, res_cap c, size_t n, res_site *o) {
    (void)s;
    bool xfer = RES_CAP_DEST(c) == RES_DEST_EXTERNAL_TRANSFER;   // size plays NO part
    *o = (res_site){ .arena = xfer ? RES_ARENA_TRANSFER : RES_ARENA_PAYLOAD_SMALL,
                     .backing = xfer ? RES_BACK_HEAP : RES_BACK_MULTIPOOL,
                     .allocator = xfer ? (void*)g_a.transfer : (void*)g_a.mp,
                     .serving = xfer ? n : mp_class_serving(g_a.mp, n),
                     .alignment = xfer ? res_cap_alignment(c) : mp_class_align(g_a.mp, n),
                     .flags = xfer ? RES_SITE_TRANSFERABLE : 0 };   // NOT WINKABLE. Ever.
    return o->alignment >= res_cap_alignment(c) ? 0 : -1;           // refuse, never under-deliver
}
static void a_free(const res_placement *s, res_backing *b, const res_site *st, void *p, size_t n,
                   res_free_mode m) { (void)s;(void)b;(void)m;      // RETAIL and WINK are IDENTICAL
    if (st->backing == RES_BACK_HEAP) mi_free(p); else ano_mem_multipool_free(g_a.mp, p, n); }
static void a_wink(const res_placement *s, res_backing *b) { (void)s;(void)b; }   // nothing to wink
const res_placement res_placement_model_a = { "model-a", a_open, a_wink, a_plan, a_alloc, a_free, a_stats };
```
Registry shards, names, dep records, conditioned metadata, payloads, parse staging, teardown records:
**all** in the one multipool. Category and lifetime are ident fields, not allocator boundaries. Level
retirement is a full retail walk with cross-level residue — A's predicted wound, **measurable**,
with no hidden per-group allocator to launder it. `RES_SITE_WINKABLE` is never set, so
`res_owned_free(RES_FREE_WINK)` does real work and A can never accidentally look like C.

### Model B — kind-major  (`place_model_b.c`)
```c
typedef struct b_kind {                 // ONE per res_kind. Its own root, its own registry shard.
    mi_heap_t *root; ano_mem_multipool *meta; ano_mem_multipool *payload;
    ano_mem_pool *chunk; mi_heap_t *transfer;
} b_kind;
static struct b_state { b_kind k[RES_KIND_COUNT]; } g_b;

static int b_open(const res_placement *s, ano_res_lifetime lt, res_backing *b) {
    (void)s; *b = (res_backing){ .root = NULL, .model_state = &g_b, .lifetime = lt };
    return 0;                            // a LIFETIME domain owns no root under B, by construction
}
static int b_plan(const res_placement *s, const res_backing *b, res_cap c, size_t n, res_site *o) {
    (void)s;(void)b;
    b_kind *k = &g_b.k[RES_CAP_KIND(c)];              // <-- the axis. Kind, not lifetime.
    if (!k->root) b_kind_open(k, RES_CAP_KIND(c));    // per-kind multipool classes tuned to that
    switch (RES_CAP_DEST(c)) {                        //     kind's recorded size histogram
    case RES_DEST_METADATA:          *o = site_mp(k->meta,    n, c, 0); break;  // KIND-MAJOR SHARD
    case RES_DEST_CHUNK:             *o = site_pool(k->chunk,    c);    break;
    case RES_DEST_EXTERNAL_TRANSFER: *o = site_heap(k->transfer, n, c,
                                            RES_SITE_TRANSFERABLE);     break;
    default:                         *o = site_mp(k->payload, n, c, 0); break;
    }
    return o->alignment >= res_cap_alignment(c) ? 0 : -1;
}
static void b_wink(const res_placement *s, res_backing *b) { (void)s;(void)b; }  // lifetime wink: no-op
// B's HOME ground — the contest harness calls this, production never does:
void res_place_b_kind_wink(res_kind k) { mi_heap_destroy(g_b.k[k].root); g_b.k[k] = (b_kind){0}; }
```
`plan()` never reads `cap.owner`. The registry shard, names and dep records of a row land in **that
row's kind's** metadata multipool — a genuine kind-major registry, not a tag in A's pool.
`RES_SITE_WINKABLE` is 0, so retiring a level is a retail walk across every kind the level touched:
B's hostile ground, exactly as B.4 predicts, honestly paid. Whole-kind teardown *is* a real O(1)
wink-out — B's home-ground number.

### Model C — lifetime-major  (`place_model_c.c`)
```c
typedef struct c_dom { ano_mem_multipool *meta; ano_mem_multipool *payload; mi_heap_t *bulk; } c_dom;

static int c_open(const res_placement *s, ano_res_lifetime lt, res_backing *b) {
    (void)s;
    mi_heap_t *root = mi_heap_new();
    c_dom *d = mi_heap_calloc(root, 1, sizeof *d);            // control struct lives in the root too
    d->meta    = ano_mem_multipool_make(ano_mem_parent_heap(root),
                   &(ano_mem_multipool_cfg){ .min_block = ANO_CACHE_LINE, .max_block = 4096 });
    d->payload = ano_mem_multipool_make(ano_mem_parent_heap(root),
                   &(ano_mem_multipool_cfg){ .min_block = ANO_CACHE_LINE, .max_block = 1u<<20 });
    d->bulk    = root;                                         // >1 MiB: direct, but IN the root heap
    *b = (res_backing){ .root = root, .transfer_root = mi_heap_new(),
                        .model_state = d, .lifetime = lt };
    b->arena[RES_ARENA_METADATA]      = d->meta;    b->kindof[RES_ARENA_METADATA]      = RES_BACK_MULTIPOOL;
    b->arena[RES_ARENA_PAYLOAD_SMALL] = d->payload; b->kindof[RES_ARENA_PAYLOAD_SMALL] = RES_BACK_MULTIPOOL;
    b->arena[RES_ARENA_PAYLOAD_BULK]  = root;       b->kindof[RES_ARENA_PAYLOAD_BULK]  = RES_BACK_HEAP;
    b->arena[RES_ARENA_TRANSFER]      = b->transfer_root; b->kindof[RES_ARENA_TRANSFER] = RES_BACK_HEAP;
    return 0;
}
static int c_plan(const res_placement *s, const res_backing *b, res_cap c, size_t n, res_site *o) {
    (void)s; c_dom *d = b->model_state;                       // kind and role play NO part
    if (RES_CAP_DEST(c) == RES_DEST_EXTERNAL_TRANSFER)
        { *o = site_heap(b->transfer_root, n, c, RES_SITE_TRANSFERABLE); return 0; }  // NOT winkable
    if (RES_CAP_DEST(c) == RES_DEST_METADATA) *o = site_mp(d->meta, n, c, RES_SITE_WINKABLE);
    else if (n + 1 > (1u << 20))              *o = site_heap(b->root, n, c,
                                                    RES_SITE_WINKABLE | RES_SITE_DIRECT_LAND);
    else                                      *o = site_mp(d->payload, n, c, RES_SITE_WINKABLE);
    return o->alignment >= res_cap_alignment(c) ? 0 : -1;
}
static void c_free(const res_placement *s, res_backing *b, const res_site *st, void *p, size_t n,
                   res_free_mode m) { (void)s;
    if (m == RES_FREE_WINK && (st->flags & RES_SITE_WINKABLE)) return;   // <-- the O(1) retire claim
    if (st->backing == RES_BACK_HEAP) mi_free(p);
    else ano_mem_multipool_free((ano_mem_multipool *)st->allocator, p, n);
}
static void c_wink(const res_placement *s, res_backing *b) { (void)s;
    mi_heap_destroy(b->root); b->root = NULL;                 // ONE call. Retire latency = this.
    if (b->transfers_outstanding == 0) { mi_heap_destroy(b->transfer_root); b->transfer_root = NULL; }
}
```
Every level resource — shard, names, deps, payloads, control records — is in the level's root.
Retirement is one `mi_heap_destroy` with **no retail walk**. That number is now real, and it is real
only because step 6 moved the >1 MiB class off the calling thread's default heap into `b->root`.

### Model D — role-split  (`place_model_d.c`)
```c
static struct d_state {                     // process-global, ROLE-keyed. No lifetime axis at all.
    mi_heap_t *root;
    ano_mem_multipool *meta;      // registry shards, names, deps, small conditioned structs, control
    ano_mem_multipool *payload;   // variable ordinary payloads
    ano_mem_pool      *chunk;     // fixed RMOS_CHUNK_MAX streaming blocks — bounded, false-on-empty
    ano_mem_stripe    *stripe;    // bulk SoA planes (vertex/index/prim), ticket/consume planes
    ano_mem_monotonic *staging;   // parse/decode/compile staging
    mi_heap_t         *transfer;  // GPU/audio/world hand-off, transferable at ANY size
} g_d;

static int d_plan(const res_placement *s, const res_backing *b, res_cap c, size_t n, res_site *o) {
    (void)s;(void)b;
    switch (RES_CAP_ROLE(c)) {                                  // <-- the axis. Role only.
    case RES_ROLE_REGISTRY: case RES_ROLE_NAME: case RES_ROLE_DEPENDENCY:
        *o = site_mp(g_d.meta, n, c, 0); break;
    case RES_ROLE_STAGING:
        *o = site_mono(g_d.staging, n, c, RES_SITE_DIRECT_LAND); break;
    case RES_ROLE_TRANSFER:
        *o = site_heap(g_d.transfer, n, c, RES_SITE_TRANSFERABLE | RES_SITE_DIRECT_LAND); break;
    default:
        if (RES_CAP_DEST(c) == RES_DEST_CHUNK)  *o = site_pool(g_d.chunk, c);
        else if (RES_CAP_DEST(c) == RES_DEST_STRIPE ||
                 RES_CAP_DEST(c) == RES_DEST_BULK)
            *o = site_stripe(g_d.stripe, n, c, RES_SITE_DIRECT_LAND);
        else *o = site_mp(g_d.payload, n, c, 0);
    }
    return o->alignment >= res_cap_alignment(c) ? 0 : -1;
}
static void d_wink(const res_placement *s, res_backing *b) { (void)s;(void)b; }   // retail-only
```
`RES_SITE_TRANSFERABLE` at **any** size — D's zero-copy hand-off rate is 100% across the whole size
distribution, its home ground, and the pointer-equality oracle proves it. Level retire is a retail
walk across every role arena: D's "multi-domain teardown complexity" wound, paid honestly.
`plan()` never reads `cap.owner` **or** `cap.kind`.

### Model E — the full C×D hybrid  (`place_model_e.c`)
```c
typedef struct e_dom {                       // the FULL role split, INSIDE each lifetime root
    ano_mem_multipool *meta, *payload;       // payload classes tuned per-kind via model_state
    ano_mem_pool      *chunk;
    ano_mem_stripe    *stripe;
    ano_mem_monotonic *staging;
    mi_heap_t         *bulk;                 // == the domain root
} e_dom;

static int e_open(const res_placement *s, ano_res_lifetime lt, res_backing *b) {
    (void)s;
    mi_heap_t *root = mi_heap_new();
    ano_mem_parent par = ano_mem_parent_heap(root);
    e_dom *d = mi_heap_calloc(root, 1, sizeof *d);
    d->meta    = ano_mem_multipool_make(par, &E_META_CFG);
    d->payload = ano_mem_multipool_make(par, e_payload_cfg_for(lt.kind));   // <-- the C x D
    d->chunk   = ano_mem_pool_make(par, RMOS_CHUNK_MAX, ANO_CACHE_LINE, RES_CHUNK_POOL_MAX);
    d->stripe  = ano_mem_stripe_make(par, &(ano_mem_stripe_cfg){ .lanes = 1, .grain = ANO_THREAD_LINE });
    d->staging = ano_mem_monotonic_make(par, 1u << 20);
    d->bulk    = root;
    *b = (res_backing){ .root = root, .transfer_root = mi_heap_new(),
                        .model_state = d, .lifetime = lt };
    /* ... arena[] wiring, every kindof[] set ... */
    return 0;
}
static int e_plan(const res_placement *s, const res_backing *b, res_cap c, size_t n, res_site *o) {
    (void)s; e_dom *d = b->model_state;                        // role x destination, WITHIN the domain
    uint8_t wink = RES_SITE_WINKABLE;
    switch (RES_CAP_ROLE(c)) {
    case RES_ROLE_REGISTRY: case RES_ROLE_NAME: case RES_ROLE_DEPENDENCY:
        *o = site_mp(d->meta, n, c, wink); break;
    case RES_ROLE_STAGING:
        *o = site_mono(d->staging, n, c, wink | RES_SITE_DIRECT_LAND); break;
    case RES_ROLE_TRANSFER:
        *o = site_heap(b->transfer_root, n, c,
                       RES_SITE_TRANSFERABLE | RES_SITE_DIRECT_LAND); break;   // NOT winkable
    default:
        if (RES_CAP_DEST(c) == RES_DEST_CHUNK)  *o = site_pool(d->chunk, c);
        else if (RES_CAP_DEST(c) == RES_DEST_STRIPE)
            *o = site_stripe(d->stripe, n, c, wink | RES_SITE_DIRECT_LAND);
        else if (n + 1 > E_BULK_THRESHOLD)
            *o = site_heap(d->bulk, n, c, wink | RES_SITE_DIRECT_LAND);
        else *o = site_mp(d->payload, n, c, wink);
    }
    return o->alignment >= res_cap_alignment(c) ? 0 : -1;
}
static void e_wink(const res_placement *s, res_backing *b) { (void)s;
    mi_heap_destroy(b->root);                                 // meta + payload + chunk + stripe +
    b->root = NULL;                                           // staging + bulk + shard + control: gone
    if (b->transfers_outstanding == 0) { mi_heap_destroy(b->transfer_root); b->transfer_root = NULL; }
}
void res_place_e_staging_wink(res_backing *b) {               // per-ingest staging reset
    ano_mem_monotonic_reset(((e_dom *)b->model_state)->staging);
}
```

**What this proves.** The five models differ in exactly three observable ways — which axis `plan()`
switches on (`nothing` / `cap.kind` / `cap.owner` / `cap.role` / `cap.owner`×`cap.role`), whether
`backing.root` is non-NULL, and whether sites are `RES_SITE_WINKABLE`. Registry shards, names,
metadata, payloads, derived objects, staging and teardown records **all** flow through
`res_owned_alloc(cap, …)`, so each model automatically owns them in its own hierarchy — nobody is
tagging default-heap allocations after the fact, and "changing only one payload pointer" is not even
possible, because the shard capability is minted per-domain and routed by the same `plan()`.

Not one line of `include/anoptic_resources.h`, `src/render/`, `src/config/`, `src/keybindings/`,
`src/resources/world/`, `src/resources/audio/`, `src/resources/script/` or `src/resources/graphics/`
changes between contestants. `git diff model-a model-e -- src/ include/` touches exactly
`src/resources/place/`.

placement_interface:
## The seam: `src/resources/resources_place.h` (module-private)

The core never names an allocator. It asks the active model to PLAN, then ALLOC at the planned site, and later FREE at the site the block remembers. Placement is dispatched through one vtable selected once at `res_registry_init`.

```c
// src/resources/resources_place.h -- the ONLY allocator vocabulary the core knows.
// A model wires whichever arenas it uses; the core treats an arena as an opaque index
// plus an opaque allocator pointer and never dereferences either.

#define RES_ARENA_MAX 16

enum res_backing_kind {                 // how the core must CALL site.allocator
    RES_BACK_MULTIPOOL = 1, RES_BACK_POOL, RES_BACK_MONOTONIC, RES_BACK_STRIPE, RES_BACK_HEAP
};

enum res_site_flags {
    RES_SITE_TRANSFERABLE   = 1u << 0,  // may leave the manager with no copy, no interior free
    RES_SITE_DIRECT_LANDING = 1u << 1,  // an IO read / decoder may write straight into it
    RES_SITE_OWN_HEAP       = 1u << 2,  // NOT reclaimed by wink(root); survives its domain
};

// The routing decision. plan+size in, the exact home out. THIS FUNCTION IS THE CONTEST.
typedef struct res_site {
    void    *allocator;     // ano_mem_multipool* / _pool* / _monotonic* / _stripe* / mi_heap_t*
    uint16_t arena;         // model-private index; free-routing and per-arena stats key
    uint8_t  backing;       // res_backing_kind
    uint8_t  flags;         // res_site_flags
    size_t   serving;       // what the arena WILL charge. Authoritative: serving_size() dies.
    size_t   alignment;     // what it WILL deliver. < plan->alignment => the plan is REFUSED.
} res_site;

// One live lifetime domain's backing, as the MODEL shapes it.
typedef struct res_backing {
    mi_heap_t        *root;                  // wink target when RES_BACKING_WINKS_WHOLE
    void             *arena[RES_ARENA_MAX];  // sparse
    uint8_t           kindof[RES_ARENA_MAX];
    void             *model_state;           // B: per-kind table. D: per-role table. E: both.
    struct res_shard *shard;                 // this domain's registry shard (below)
    ano_res_lifetime  lifetime;
    uint32_t          flags;                 // RES_BACKING_WINKS_WHOLE
    size_t            outstanding_parcels;   // teardown barrier for RES_SITE_OWN_HEAP transfers
} res_backing;

typedef struct res_placement {
    const char *name;                        // "global-pool" | "scoped-pool" | "model-a".."model-e"
    int   (*open) (const struct res_placement *, ano_res_lifetime, res_backing *out);
    void  (*wink) (const struct res_placement *, res_backing *);
    int   (*plan) (const struct res_placement *, res_backing *,
                   const res_place_plan *, size_t size, res_site *out);   // route only, no alloc
    void *(*alloc)(const struct res_placement *, res_backing *, const res_site *, size_t);
    void  (*free) (const struct res_placement *, res_backing *, const res_site *, void *, size_t);
    ano_mem_stats (*arena_stats)(const struct res_placement *, const res_backing *, uint16_t arena);
} res_placement;

const res_placement *res_placement_active(void);   // ANO_RES_PLACEMENT, read once at init
const char          *res_placement_name(void);     // logged at INFO, reported in stats
```

`res_place_plan` keeps its six declared axes and LOSES `bool transfer_compatible` — transferability is now an OUTPUT of `plan()` (`RES_SITE_TRANSFERABLE`), never a caller-computed `size + 1 > RES_POOL_MAX` duplicated at three call sites. `res_owned_block` loses `bool pooled` and gains `res_site site`, so a free routes back to the exact arena it came from with no re-derivation.

Two flags carry the whole wink-out difference:

- `RES_BACKING_WINKS_WHOLE` set (C, E): `ano_res_domain_retire` invalidates publication, crosses the grace barrier, drops the shard, then calls `wink()` = `mi_heap_destroy(b->root)`. **No retail walk.** That is the claim, now measurable.
- flag clear (A, B, D): the core walks the domain's shard bindings calling `placement->free(site,...)` per block, then `wink()` reclaims the shard's own records. That is the wound, now measurable.

A Debug assertion after every `wink()` checks that the domain's `live_bytes` returned to zero — a model that lies about `WINKS_WHOLE` fails loudly instead of double-freeing quietly.

## The two-layer registry (spec §1, literally)

```c
// PERMANENT. Root-owned, non-moving 64-entry chunks. 40 bytes. This is all §1 permits here.
typedef struct res_ident {
    uint64_t rid;               // fnv1a64 over the key text, seeded by key namespace
    uint64_t rid2;              // SECOND independent hash: collision refusal never reads name TEXT
    uint32_t name_len;
    uint32_t generation;
    uint16_t shard_owner;       // which domain's shard holds the binding (0 = unbound)
    uint16_t kind;              // dense runtime kind id (see res_ext)
    uint32_t shard_ref;         // index into that shard's binding table
    uint8_t  tombstone, derived, _pad[2];
} res_ident;

// PER DOMAIN, allocated THROUGH the seam with role=RES_ROLE_REGISTRY and the binding's own
// kind, so Model B lands it in the kind's metadata pool and Model E in the domain's.
typedef struct res_binding {
    res_owned_block payload;        // carries its res_site
    res_owned_block name_storage;   // the name TEXT lives and dies with the domain
    res_owned_block dep_storage;
    uint32_t        dep_count;
    uint64_t        content_hash;   // hot reload confirms bytes, never mtime
    res_source_id   source;         // which mount/pack won, for reload candidacy
    uint32_t        ident_slot;
} res_binding;

typedef struct res_shard {          // non-moving 32-binding chunks from the domain's METADATA arena
    res_binding    *chunks[RES_SHARD_CHUNKS];
    res_owned_block chunk_storage[RES_SHARD_CHUNKS];
    uint32_t        count;
} res_shard;
```

Collision refusal compares `{rid, rid2, name_len}` and never touches name text — which is exactly what makes it legal for the name to live in the owning domain's shard and wink out with it (A.2 "Registry storage"). The rid→slot open-addressed map stays root-owned and is one `uint32_t` per slot: the "deliberately small permanent directory" §1 demands, and nothing else.

## The three consume verbs (public, additive)

```c
// include/anoptic_resources.h -- ADDITIVE. anores_t, ano_res_lifetime, ano_res_read,
// ano_res_get/bytes/unload keep their exact shape and semantics.

// 1. BORROW. Kind-checked: a font handle can no longer be reinterpreted as a scene block.
anostr_t ano_res_bytes_typed(const ano_res_read *, anores_t, uint32_t kind_tag);

// 2. DESTRUCTIVE TRANSFER. Not a raw pointer: a counted parcel that knows its own home.
typedef struct ano_res_parcel { void *data; size_t size; uint64_t token; uint32_t _site[4]; }
        ano_res_parcel;
int  ano_res_take(ano_res_lifetime, anores_t, ano_res_parcel *out);  // 0 / -1 / -2 reader-stalled
void ano_res_parcel_free(ano_res_parcel *);                          // routes home through the site
bool ano_res_parcel_zero_copy(const ano_res_parcel *);               // the pointer-equality oracle

// 3. DERIVE. Every conditioned/decoded artifact in the engine enters through this one door.
anores_t ano_res_derive(ano_res_lifetime, const ano_res_read *, anores_t src, uint32_t kind_tag);

// Dependency disclosure + prefetch: the manager already knows; now it can be asked.
typedef struct ano_res_dep { uint64_t rid; uint32_t kind_tag; uint32_t flags; } ano_res_dep;
size_t ano_res_deps(const ano_res_read *, anores_t, ano_res_dep *out, size_t cap);
int    ano_res_prefetch(ano_res_lifetime, const char *logical, ano_res_prefetch_report *out);

// Explicit cross-lifetime policy. No refcount, ever.
int ano_res_promote  (ano_res_lifetime from, ano_res_lifetime to, anores_t h, anores_t *out);
int ano_res_duplicate(ano_res_lifetime from, ano_res_lifetime to, anores_t h, anores_t *out);
int ano_res_share    (ano_res_lifetime from, anores_t h, anores_t *out);   // -> SHARED_IMMUTABLE
```

`ano_resgfx_model`, `ano_resgfx_image`, `ano_resaudio_decode`, `ano_resscript_compile`, `ano_restext_bake` are all one-line wrappers over `ano_res_derive` with their kind tag. That is the modularity claim cashed out.

five_model_proof:
The seam is six function pointers. Below, each model is one TU. **The core, the public header, `anores_t`, `ano_res_get/bytes/take/derive/unload`, the renderer, the audio sink, the VM, config, keybindings and world are byte-identical across all five.** The only thing that changes is which `res_placement *` `res_placement_active()` returns.

The load-bearing mechanism: `res_shard_alloc()` — the core's allocator for names, binding records, dependency arrays and placement metadata — builds a plan carrying `{kind, lifetime, role=REGISTRY/NAME/DEPENDENCY}` and routes it through the *same* `plan()`. So registry shards land wherever the model says, with no core knowledge and no per-model core branch. That is what makes B.1's "changing only one payload pointer is not a contestant" satisfiable without touching a consumer.

---
**Model A — one complete multipool.** `model_state = NULL`. One process root heap, one multipool. Every domain's backing points at the *same* arena[0].

```c
static int a_open(const res_placement *s, ano_res_lifetime lt, res_backing *b) {
    *b = (res_backing){ .root = g_a.root, .lifetime = lt, .flags = 0 };  // NOT winks-whole
    b->arena[0] = g_a.pool;  b->kindof[0] = RES_BACK_MULTIPOOL;          // ONE pool for everything
    b->shard = res_shard_make(b);                                        // -> arena[0], by construction
    return 0;
}
static int a_plan(const res_placement *s, res_backing *b, const res_place_plan *p,
                  size_t n, res_site *out) {
    (void)p;                                    // kind, lifetime, role: registry FIELDS, not boundaries
    size_t cls = a_class_of(n);
    *out = (res_site){ .allocator = b->arena[0], .arena = 0, .backing = RES_BACK_MULTIPOOL,
                       .serving = cls, .alignment = cls < 4096 ? cls : 4096,
                       .flags = n > A_MAX_BLOCK ? RES_SITE_TRANSFERABLE : 0 };
    return out->alignment >= p->alignment ? 0 : a_plan_aligned_class(b, p, n, out);
}
static void a_wink(const res_placement *s, res_backing *b) { res_shard_free_retail(b); }
```

Its predicted wound is *forced into the numbers*: a level retire is a retail walk of the shard (`WINKS_WHOLE` clear), `ano_res_take` under 1 MiB has no `RES_SITE_TRANSFERABLE` so it **copies** and `releases_copied` says so, and cross-level residue shows up in `ano_res_domain_stats`. No hidden per-group allocator can make A look like C — there is nowhere to hide one, because the core acquires *nothing* except through `plan()`.

---
**Model B — kind-major.** `model_state` = the process kind table. Lifetime is a registry field.

```c
typedef struct b_kind { mi_heap_t *heap; ano_mem_multipool *meta, *payload; ano_mem_pool *chunk; }
        b_kind;                                          // lazily created, class-tuned per kind
static b_kind g_b[RES_KIND_MAX];

static int b_plan(const res_placement *s, res_backing *b, const res_place_plan *p,
                  size_t n, res_site *out) {
    b_kind *k = b_kind_for(p->kind);                      // <-- THE axis
    bool meta = p->role == RES_ROLE_REGISTRY || p->role == RES_ROLE_NAME
             || p->role == RES_ROLE_DEPENDENCY;
    ano_mem_multipool *mp = meta ? k->meta : k->payload;
    *out = (res_site){ .allocator = mp, .arena = (uint16_t)p->kind, .backing = RES_BACK_MULTIPOOL,
                       .serving = mp_class_size(mp, n), .alignment = mp_class_align(mp, n) };
    return 0;
}
```

`res_shard_alloc` passes the binding's own kind, so a domain's shard is **split across kind metadata pools** — B's honest structure and its honest wound (multi-kind teardown complexity). `b_open` leaves `WINKS_WHOLE` clear: a level retire is a retail walk across every kind it touched. Whole-KIND teardown is a *real* wink through the same vtable: `res_placement_b_retire_kind(kind)` = `mi_heap_destroy(g_b[kind].heap)` — the subsystem-restart home ground. No kind is a tag in a shared pool, and B gets the dense countable kind axis it needs from `res_kind_of()`.

---
**Model C — lifetime-major.** One heap and one multipool per domain. `WINKS_WHOLE` set.

```c
static int c_open(const res_placement *s, ano_res_lifetime lt, res_backing *b) {
    *b = (res_backing){ .lifetime = lt, .flags = RES_BACKING_WINKS_WHOLE };
    b->root = mi_heap_new();
    b->arena[0] = ano_mem_multipool_make(ano_mem_parent_heap(b->root), &c_cfg); // full distribution
    b->kindof[0] = RES_BACK_MULTIPOOL;
    b->arena[1] = b->root; b->kindof[1] = RES_BACK_HEAP;                        // oversize
    b->shard = res_shard_make(b);                        // -> arena[0]: dies WITH the heap
    return b->root && b->arena[0] ? 0 : -1;
}
static void c_wink(const res_placement *s, res_backing *b) { mi_heap_destroy(b->root); }
                                                        // one call. NO retail walk. THE claim.
```

`c_plan` switches only on size. Registry shard, names, deps, payloads and teardown records all live in the domain's own multipool, so retire latency really *is* one `mi_heap_destroy` — and the core lets it be, because `WINKS_WHOLE` tells the retire path to skip per-block frees. This is measurable for the first time, because today every >1 MiB payload is a `mi_malloc_aligned` on the *calling thread's default heap*, not the domain heap, so the biggest blocks were never in the heap being measured. C's hostile ground is real and unhidden: `c_plan` never sets `RES_SITE_TRANSFERABLE`, so every take copies.

---
**Model D — role-split.** Process-wide role arenas. Lifetime is a registry field.

```c
static struct { ano_mem_multipool *meta, *payload; ano_mem_pool *chunk;
                ano_mem_stripe *stripe; mi_heap_t *transfer_heap; } g_d;

static int d_plan(const res_placement *s, res_backing *b, const res_place_plan *p,
                  size_t n, res_site *out) {
    switch (p->role) {                                         // <-- THE axis
    case RES_ROLE_REGISTRY: case RES_ROLE_NAME: case RES_ROLE_DEPENDENCY:
        return d_site(out, g_d.meta, D_ARENA_META, RES_BACK_MULTIPOOL, n, 0);
    case RES_ROLE_STAGING:
        return p->destination == RES_DEST_STAGING && n == RMOS_CHUNK_MAX
             ? d_site(out, g_d.chunk, D_ARENA_CHUNK, RES_BACK_POOL, n, 0)   // bounded ano_mem_pool
             : d_site(out, b->arena[D_ARENA_STAGING], D_ARENA_STAGING, RES_BACK_MONOTONIC, n, 0);
    case RES_ROLE_TRANSFER:                                    // zero-copy at ANY size: D's home
        return d_site(out, g_d.transfer_heap, D_ARENA_TRANSFER, RES_BACK_HEAP, n,
                      RES_SITE_TRANSFERABLE | RES_SITE_DIRECT_LANDING | RES_SITE_OWN_HEAP);
    case RES_ROLE_DERIVED:
        return p->destination == RES_DEST_BULK
             ? d_site(out, g_d.stripe, D_ARENA_STRIPE, RES_BACK_STRIPE, n, RES_SITE_DIRECT_LANDING)
             : d_site(out, g_d.payload, D_ARENA_PAYLOAD, RES_BACK_MULTIPOOL, n, 0);
    default:
        return d_site(out, g_d.payload, D_ARENA_PAYLOAD, RES_BACK_MULTIPOOL, n,
                      RES_SITE_DIRECT_LANDING);
    }
}
```

`ano_res_take` of a 40 KiB decoded thumbnail moves **zero-copy** under D and copies under A/C — the "zero-copy rate across the full size distribution" B.6 names as its battlefield, now measurable by `ano_res_parcel_zero_copy()`. `d_wink` is a retail walk routing each block back by `site.arena`; every resource records the role domains it spans (its bindings' sites), and retire/release handles each exactly once. D is also the reason `ano_mem_stripe` must actually exist rather than remain "a documented idea".

---
**Model E — the full C×D hybrid.** Lifetime-major heaps, role split *inside* each one.

```c
static int e_open(const res_placement *s, ano_res_lifetime lt, res_backing *b) {
    *b = (res_backing){ .lifetime = lt, .flags = RES_BACKING_WINKS_WHOLE };
    b->root = mi_heap_new();
    ano_mem_parent par = ano_mem_parent_heap(b->root);
    b->arena[E_META]     = ano_mem_multipool_make(par, &e_meta_cfg);
    b->arena[E_PAYLOAD]  = ano_mem_multipool_make(par, &e_payload_cfg);
    b->arena[E_CHUNK]    = ano_mem_pool_make(par, RMOS_CHUNK_MAX, ANO_CACHE_LINE, 8);
    b->arena[E_STRIPE]   = ano_mem_stripe_make(par, &e_stripe_cfg);
    b->arena[E_STAGING]  = ano_mem_monotonic_make(par, 1u << 20);
    b->arena[E_TRANSFER] = mi_heap_new();          // OWN heap: survives wink while parcels fly
    b->shard = res_shard_make(b);                  // -> E_META: dies with the domain
    return 0;
}
static int e_plan(const res_placement *s, res_backing *b, const res_place_plan *p,
                  size_t n, res_site *out) {
    switch (p->role) {                             // <-- role INSIDE the lifetime domain
    case RES_ROLE_REGISTRY: case RES_ROLE_NAME: case RES_ROLE_DEPENDENCY:
        return e_site(out, b->arena[E_META], E_META, RES_BACK_MULTIPOOL, n, 0);
    case RES_ROLE_STAGING:
        return n == RMOS_CHUNK_MAX
             ? e_site(out, b->arena[E_CHUNK], E_CHUNK, RES_BACK_POOL, n, 0)
             : e_site(out, b->arena[E_STAGING], E_STAGING, RES_BACK_MONOTONIC, n, 0);
    case RES_ROLE_TRANSFER:
        return e_site(out, b->arena[E_TRANSFER], E_TRANSFER, RES_BACK_HEAP, n,
                      RES_SITE_TRANSFERABLE | RES_SITE_DIRECT_LANDING | RES_SITE_OWN_HEAP);
    case RES_ROLE_DERIVED:
        return p->destination == RES_DEST_BULK
             ? e_site(out, b->arena[E_STRIPE], E_STRIPE, RES_BACK_STRIPE, n, RES_SITE_DIRECT_LANDING)
             : e_site(out, b->arena[E_PAYLOAD], E_PAYLOAD, RES_BACK_MULTIPOOL, n, 0);
    default:
        return e_site(out, b->arena[E_PAYLOAD], E_PAYLOAD, RES_BACK_MULTIPOOL, n,
                      RES_SITE_DIRECT_LANDING);
    }
}
static void e_wink(const res_placement *s, res_backing *b) {
    ano_mem_monotonic_destroy(b->arena[E_STAGING]);          // staging winks after adoption
    if (b->outstanding_parcels == 0) mi_heap_destroy(b->arena[E_TRANSFER]);
    else                             e_defer_transfer_heap(b);  // retire returns -2; caller retries
    mi_heap_destroy(b->root);                                   // whole domain, one call
}
```

E gets **no credit for components that do not exist**: `ano_mem_stripe` is a real fourth allocator landed in `include/anoptic_memory_pools.h` + `src/memory/pools.c` (lane-isolated allocation at `ANO_THREAD_LINE` grain, plus `ano_mem_stripe_planes()` carving N parallel SoA planes from one parent acquisition), shipping with a resource consumer (`E_STRIPE` serving bulk SoA scene planes) and a home bench, per A.2's roster rule.

---
**What the core does, identically, for all five:**

```c
static int owned_alloc_locked(const res_place_plan *p, size_t n, res_owned_block *out) {
    res_backing *b = backing_of(p->lifetime);  if (!b) return -1;
    const res_placement *P = res_placement_active();
    res_site site;
    if (P->plan(P, b, p, n + 1, &site) != 0) return -1;
    if (site.alignment < (p->alignment ? p->alignment : ANO_CACHE_LINE)) return -1;  // honest refusal
    void *q = P->alloc(P, b, &site, n + 1);    if (!q) return -1;
    *out = (res_owned_block){ .data = q, .size = n, .site = site, .plan = *p };
    res_account(RES_ACCT_ALLOC, p, &site, n);
    return 0;
}
```

Consumers never see `res_site`, `res_backing`, `res_placement`, or an arena. `include/anoptic_resources.h` gains only additive surface. **Verified against the tree: `src/resources/world/res_world.c`, `src/config/`, `src/keybindings/`, `src/text/` and the renderer reference no placement symbol today, so they are untouched by construction — and if a placement change ever forces an edit to one of them, A.4 bullet 2's neutral-interface requirement has been violated and this design is wrong.**

