  // The routing decision. Pure: allocates nothing, mutates nothing. THIS is the contest.
  typedef struct res_site {
      uint32_t root;          // index into res_placement.root[]
      uint8_t  arena;         // res_arena_id
      uint8_t  backing;       // res_backing
      uint16_t cell;          // telemetry cell, resolved ONCE at plan time (see below)
      size_t   serving;       // what the arena will actually CHARGE (asked, never re-derived)
      size_t   alignment;     // what the arena will actually DELIVER (>= plan->alignment)
      bool     direct_landing;// an IO read or a decoder may write straight into this block
      bool     transferable;  // may leave the manager with no copy and no interior free
      bool     winkable;      // dies with a lifetime heap destroy; no retail free needed
  } res_site;

res_owned_block CHANGES: `bool pooled` is deleted, `res_site site` is added. A free therefore routes back to the exact arena it came from, in any model, with no re-derivation. serving_size() (registry:137, which re-derives the multipool's class math and whose `n > RES_POOL_MAX` branch is dead) is DELETED; res_site.serving is authoritative.

--- 3. THE ROOT AXIS: the one thing that actually differs between the five models ---

  typedef enum res_root_axis {
      RES_ROOT_SINGLE = 1,   // one process root heap                (A)
      RES_ROOT_KIND,         // one root heap per res_kind           (B)
      RES_ROOT_LIFETIME,     // one root heap per lifetime domain    (C, E)
      RES_ROOT_ROLE,         // one root heap per role class         (D)
  } res_root_axis;

  typedef struct res_root {              // SoA over roots; model-agnostic
      mi_heap_t *heap;
      void      *arena[RES_ARENA_COUNT]; // ano_mem_multipool*/pool*/monotonic*/stripe*/heap
      uint8_t    backing[RES_ARENA_COUNT];
      uint32_t   key;                    // kind | lifetime.owner | role, per axis
      size_t     live_blocks;
      bool       live;
  } res_root;

  typedef struct res_placement {
      const res_model *model;
      res_root root[RES_ROOT_MAX];       // max(RES_KIND_COUNT, RES_DOMAIN_MAX, RES_ROLE_COUNT)
      mi_heap_t *transfer_heap;          // process-lived; NEVER a child of a winkable root
      uint32_t root_count;
  } res_placement;

--- 4. THE MODEL IS DATA ---

  typedef struct res_arena_spec {
      uint8_t backing;
      uint32_t min_block, max_block;     // multipool
      uint32_t block_size, max_blocks;   // pool
      uint32_t grain;                    // stripe (0 = ANO_THREAD_LINE)
      uint32_t first_slab;               // monotonic
      bool transferable, direct_landing;
  } res_arena_spec;

  typedef struct res_model {
      const char *name;                  // "global-pool" | "scoped-pool" | "model-a".."model-e"
      res_root_axis root_axis;
      size_t small_max;                  // SMALL/BULK split; SIZE_MAX = one class serves all
      bool   needs_teardown_records;     // a non-winkable model must keep a per-domain block
                                         // list -- and PAY for it from its OWN metadata arena
      res_arena_spec arena[RES_ARENA_COUNT];                  // uniform roster
      const res_arena_spec (*arena_by_key)[RES_ARENA_COUNT];  // per-root-key roster: B tunes
      uint32_t arena_by_key_count;                            // by kind, E tunes by lifetime
      uint8_t route[RES_ROLE_COUNT][RES_DEST_COUNT];     // the routing PLANE; COUNT = refuse
      int8_t  kind_route[RES_KIND_COUNT][RES_ROLE_COUNT]; // -1 = fall through (B's override)
      int (*plan_hook)(const res_model *, const res_place_plan *, size_t, res_site *inout);
  } res_model;

--- 5. THE FUNCTIONS (the whole seam; 8 calls) ---

  int   res_place_init(const char *model_name);   // once, at res_registry_init
  const char *res_place_name(void);               // logged at INFO; reported in stats

  int   res_place_domain_open(ano_res_lifetime lt);      // new root, or just a new stats key
  bool  res_place_domain_winkable(ano_res_lifetime lt);  // may this domain die by heap destroy?
  void  res_place_domain_wink(ano_res_lifetime lt);      // ONE mi_heap_destroy, no retail walk

  int   res_place_plan(const res_place_plan *p, size_t size, res_site *out); // pure route
  void *res_place_alloc(const res_site *s, size_t size);
  void  res_place_free (const res_site *s, void *p, size_t size);
  ano_mem_stats res_place_arena_stats(uint32_t root, res_arena_id arena);

res_owned_alloc(plan, size, out) KEEPS ITS EXACT SIGNATURE. Its body becomes:
    res_site site;
    if (res_place_plan(plan, size, &site) != 0) return -1;
    void *p = res_place_alloc(&site, size + 1);  if (!p) return -1;
    *out = (res_owned_block){ .data=p, .size=size, .serving=site.serving,
                              .plan=*plan, .site=site };
    res_tel_alloc(site.cell, size, site.serving);
block_free_locked becomes res_place_free(&b->site, b->data, b->size + 1) + res_tel_free(...).
Every existing caller (res_graphics, save_adopt, row_bind, grow_slots) is source-unchanged except that it stops setting transfer_compatible.

--- 6. THE PLANE PRIMITIVE (why this is SOA-PLANES and not merely a vtable) ---

  #define RES_PLANE_GRAIN 64u   // COMPILE-TIME CONSTANT, deliberately NOT ANO_CACHE_LINE:
                                // a baked block's interior offsets are an ABI and may not
                                // change with the target's cache line (128 on arm64/Apple).

  // Pure layout. A deterministic function of (hdr_bytes, count, elem_size[], n_planes) ONLY.
  // The bake, the pack, and the hostile validator all depend on exactly this function.
  size_t res_plane_layout(size_t hdr_bytes, size_t count, const size_t *elem_size,
                          size_t n_planes, uint64_t *out_off);

Every conditioned resource in the engine is now ONE plane-set block: header + K planes at
RES_PLANE_GRAIN-aligned offsets, zero interior pointers.
  - graphics scene: vertices | indices | prims | meshes | nodes | children | materials |
                    samplers | images | image_bytes | skins | joints | animations |
                    anim_channels | anim_samplers | anim_keys | cameras | lights | roots
  - audio PCM:      one f32 plane PER CHANNEL (planar, not interleaved -- the mixer walks one
                    plane per channel; the SoA thesis paying rent inside a decoder)
  - script bytecode: code | constants | names | debug_lines
  - GPU binding:    geometry_pool_index | material_index | bindless_index
  - level:          assets | instances | lights | scripts | audio | strings
  - font bake:      glyph_metrics | atlas_uv | atlas_pixels

ONE framing (res_block_hdr: magic, version, layout_id, block_hash, plane_count, off[]),
ONE validator (res_block_open), ONE bake path, ONE pack entry type, ONE hostile-input gate.
res_place_alloc delivers the block BASE at max(ANO_CACHE_LINE, RES_PLANE_GRAIN), so plane
bases are cache-aligned on 64-byte-line machines. layout_id = a compile-time FNV over
sizeof/alignof of every struct in the block plus RES_PLANE_GRAIN: struct-layout drift between
builder and runtime is a clean refusal, not a silent misread of a POD image.

ano_mem_stripe (RES_ARENA_PLANE) is for LANE-isolated planes where no bake ABI exists and two
writers must not share a line: reader lanes (g_readers[64] is today a static array of 16-byte
lanes that false-share across 1.2M raced reads), the telemetry cells, and Stage C's ticket
state / consume planes. grain = ANO_THREAD_LINE there, because there is nothing to freeze.

--- 7. TELEMETRY IS A PLANE, AND IT IS FREE ON THE HOT PATH ---

The naive attribution cube is 10x6x7x9 x 21 counters -- megabytes, and it would wreck the very
cache it claims to measure. Instead: a 19-bit packed key (kind|life|role|op|dest), a 1024-entry
open-addressed cell table, and SoA counter planes:

  uint32_t cell_key[N];
  uint64_t cell_alloc_bytes[N], cell_serving[N], cell_allocs[N], cell_frees[N],
           cell_copies[N], cell_copy_bytes[N], cell_transfers[N], cell_promotions[N], ...;

The hash runs ONCE, inside res_place_plan, and the index is cached in res_site.cell. The
alloc/free/copy/transfer hot path is a plain non-atomic plane store at a known index --
owner-thread-only by construction, so Stage C's mutex deletion does not silently turn telemetry
into a data race. res_account_copy and res_account_transfer stop doing `(void)plan;`
(registry:222, :233) and charge site.cell. Snapshots are copy-outs; readers never touch the
live planes.

  ano_res_allocator_stats res_stats_axis(res_stat_axis axis, uint32_t key);   // internal
  int ano_res_domain_stats(ano_res_lifetime lt, ano_res_allocator_stats *out); // public

domain_grammar:
LIFETIME DOMAINS
ano_res_lifetime_kind gains ANO_RES_LIFETIME_SHARED_IMMUTABLE, appended AFTER TOOL_IMPORT -- the bound check at resources_registry.c:601-602 is `kind > ANO_RES_LIFETIME_TOOL_IMPORT`, so inserting it anywhere else silently breaks domain_open. A SHARED_IMMUTABLE domain is engine-lived in Stage A: retiring one while any other domain is live is REFUSED with one ERROR. That is how cross-lifetime sharing is resolved with NO reference count, silent or otherwise -- an alias into a domain that cannot die is not a lifetime hazard, and it needs no count to prove it.

THE ALIAS BUG (xlifetime-silent-alias) -- fixed structurally, not with a comment.
ano_res_get's hit path (registry:775-779) returns the resident handle WITHOUT comparing row->payload.plan.lifetime to the requested lifetime. It is latent only because production loads everything into the immortal ENGINE domain; the instant the level squad opens a real WORLD_LEVEL domain it becomes a live use-after-retire (level B's handles point into level A's mi_heap, and ano_res_domain_retire calls mi_heap_destroy on it). Replaced by an explicit policy branch:

  typedef enum ano_res_share {
      ANO_RES_SHARE_REFUSE = 0,  // default: a cross-domain hit -> sentinel + one ERROR line
      ANO_RES_SHARE_ALIAS,       // legal ONLY when the resident owner is SHARED_IMMUTABLE
      ANO_RES_SHARE_PROMOTE,     // move the payload into the named target domain
      ANO_RES_SHARE_DUPLICATE,   // an independent second payload under "<logical>@<owner>"
  } ano_res_share;
  anores_t ano_res_get_ex(ano_res_lifetime, const char *logical, ano_res_share);
  // ano_res_get(lt, l) == ano_res_get_ex(lt, l, ANO_RES_SHARE_REFUSE). Handle shape unchanged.

  int ano_res_promote  (ano_res_lifetime from, ano_res_lifetime to, anores_t h, anores_t *out);
  int ano_res_duplicate(ano_res_lifetime from, ano_res_lifetime to, anores_t h, anores_t *out);

PROMOTE: res_place_plan the destination site; if src.site.transferable && dst.site.transferable && they share a root -> pointer move, zero copy, charged as a transfer. Otherwise allocate + copy + charge exactly one copies/bytes_copied/promotions. Then rewrite the bind record's lifetime, decrement from->live_rows / increment to->live_rows, publish a FRESH res_pub at generation+1, and epoch-retire the old descriptor. No path returns a handle whose payload lives in a domain the caller did not name and cannot retire.

DUPLICATE SCHEMA -- the decision the ledger says one person must make, made:
duplicates are keyed "<logical>@<owner_index>", NOT the generation. Owner indexes are reused after retire, so a duplicate row is re-BOUND rather than accumulating; the permanent identity-slot cost is bounded at RES_DOMAIN_MAX duplicates per logical path, forever. The registry stays strictly one row per rid (row_bind, registry:358), which is the constraint that made this a schema decision in the first place.

res_disposition_allowed becomes a PURE predicate: it stops mutating stats.promotions / stats.duplications when a test merely ASKS whether a disposition is legal (registry:268-276). Today those counters count questions, not events, and any promotion-cost number is polluted by them.

RESERVED KEY GRAMMAR -- kills the derived-key type-confusion hole at its root.
'#' and '@' are legal logical-path bytes today (byte_ok, resources_core.c:107-109), so ano_res_get(lt, "models/viking_room.gltf#gfx") hits the conditioned scene's registry slot and ano_res_bytes hands the SCENE BLOCK back as if it were file bytes -- no kind is recorded and no kind is checked. Two independent defenses:
  1. res_path_validate REFUSES '#' and '@'. A filesystem logical path can never name a derived key, and a derived key can never be resolved from the filesystem.
  2. Derived and synthetic keys are constructed ONLY by
       int res_key_derived(const char *src, const char *tag, char *out, size_t cap);
       int res_key_ranged (const char *src, uint64_t off, size_t len, char *out, size_t cap);
     and validated by res_key_validate, which permits the reserved bytes. The identity plane records the res_kind, and EVERY typed accessor (ano_resgfx_scene, ano_resaudio_pcm, ano_resscript_program, ano_reslevel_view) refuses a kind-mismatched handle BEFORE it dereferences anything.

REGISTRY SHARD OWNERSHIP -- the split spec section 1 demands.
res_row (a 7-field AoS struct today, allocated wholly from root_plan()'s ENGINE domain, registry:331-342) is split:

  PERMANENT IDENTITY PLANES -- root-owned, never move, chunked in 4096-slot chunks so the
  directory GROWS by appending a chunk instead of freezing at RES_SLOT_MAX:
      uint64_t *plane_rid[C]; uint64_t *plane_rid2[C]; uint32_t *plane_gen[C];
      uint16_t *plane_namelen[C]; uint8_t *plane_kind[C]; uint8_t *plane_flags[C];
      _Atomic(res_pub *) *plane_dir[C];   // the publication directory, also chunked
      res_bind * *plane_bind[C];          // -> the domain-owned shard; NULL when unbound

  DOMAIN SHARD -- allocated by the MODEL, from the OWNING domain's RES_ARENA_METADATA:
      typedef struct res_bind {
          char *name; res_dependency_meta *deps; uint32_t dep_count;
          res_owned_block payload;               // carries res_site
          uint64_t content_hash;                 // hot reload confirmation
          uint32_t source_mount; uint8_t source_kind;  // which mount won: loose vs pack
      } res_bind;

It dies with the domain. Names, dependency records and placement metadata are therefore IN the hierarchy being measured: a WORLD_LEVEL that loads 5000 resources no longer permanently grows the ENGINE domain by 5000 names + 5000 rows + dep arrays that level retirement reclaims none of.

THE NAME HAZARD -- the thing that makes the above safe, and a prerequisite, not a follow-up.
row_bind's collision refusal does `memcmp(row->name, logical, len)` (registry:363) on a row whose payload may already be retired; its own comment says names live in root "so collision diagnostics survive retirement". Move the name into the domain shard naively and that memcmp reads freed memory -- an ASan find at best, silent acceptance of a colliding rid at worst. So the identity plane carries a SECOND independent 64-bit hash (rid2 = FNV-1a-64 over the same bytes with a different offset basis) plus name_len, and collision refusal compares {rid, rid2, name_len} and NEVER touches the name text. Diagnostics print the name only while the binding is live.

DEPENDENCY DISCLOSURE + PREFETCH. Deps are write-only today: built at res_graphics.c:572-591, stored at registry:964-975, read by NOBODY -- and the renderer re-derives the same set by hand (ano_GltfParser.c:159-177) because it cannot ask.
  int ano_res_deps(const ano_res_read *, anores_t h, ano_res_dep *out, size_t cap);
  int ano_res_prefetch(ano_res_lifetime, const char *logical, ano_res_share policy);
Prefetch is owner-thread-synchronous in Stage A: load, read back the disclosed set, transitively resolve the closure into the SAME domain (or the shared/promoted domain the per-asset policy names), with cycle refusal, a bounded depth, and per-edge accounting. Deps are copied OUT to the caller; no pointer into row storage hangs off res_pub, which Stage C freezes as the lock-free read descriptor (C.4: the reader never touches the mutable map).

PROMOTION AND SHARING ARE NEVER SILENT: ALIAS / PROMOTE / DUPLICATE / TRANSFER each charge their own counter and their own telemetry cell, and the level manifest names the policy per asset. There is no reference count anywhere in the manager.

five_model_proof:
THE CLAIM: each model is a `static const res_model` literal. No registry code, no consumer code, no public header changes. res_owned_alloc/res_owned_free keep their exact signatures. res_graphics.c, res_world.c, src/config/, src/keybindings/ and the renderer reference no placement symbol -- verified -- so they are untouched BY CONSTRUCTION.

Shared idiom: route_all(m, arena) fills route[role][dest]; route_role(m, role, arena) overrides one role. Written as init helpers because C23 has no range designators; the model is still pure data.

--- MODEL A: one complete multipool ---
static res_model MODEL_A = {
  .name = "model-a",
  .root_axis = RES_ROOT_SINGLE,          // ONE root heap for the entire manager
  .small_max = SIZE_MAX,                 // no size split: one multipool serves EVERYTHING
  .needs_teardown_records = true,        // A cannot wink out a level: it must retail-free
  .arena = {
    [RES_ARENA_SMALL]    = { RES_BACK_MULTIPOOL, .min_block=64, .max_block=1u<<24,
                             .direct_landing=true },
    [RES_ARENA_TRANSFER] = { RES_BACK_HEAP, .transferable=true, .direct_landing=true },
  },
};
// route_all(&MODEL_A, RES_ARENA_SMALL);   // registry, names, deps, payloads, derived, STAGING
// route_role(&MODEL_A, RES_ROLE_TRANSFER, RES_ARENA_TRANSFER);
A has NO monotonic staging arena and NO per-kind arena: parse staging churns the one multipool retail, exactly as B.3 demands ("a hidden monotonic lifetime heap may not make Model A look like Model C or E"). res_place_domain_winkable(any) == false, so ano_res_domain_retire walks A's own teardown records -- which A pays for out of its own multipool. Its predicted wound (repeated partial lifetime retirement, cross-level residue) is measured, not outsourced.

--- MODEL B: kind-major ---
static const res_arena_spec B_ARENAS[RES_KIND_COUNT][RES_ARENA_COUNT] = {
  [RES_KIND_IMAGE_ENCODED] = {
      [RES_ARENA_METADATA] = {RES_BACK_MULTIPOOL, .min_block=64,   .max_block=4096},
      [RES_ARENA_SMALL]    = {RES_BACK_MULTIPOOL, .min_block=4096, .max_block=1u<<22} },
  [RES_KIND_SHADER] = {
      [RES_ARENA_METADATA] = {RES_BACK_MULTIPOOL, .min_block=64,   .max_block=1024},
      [RES_ARENA_SMALL]    = {RES_BACK_MULTIPOOL, .min_block=256,  .max_block=1u<<16} },
  [RES_KIND_AUDIO_PCM] = {
      [RES_ARENA_PLANE]    = {RES_BACK_STRIPE,    .grain=ANO_THREAD_LINE},
      [RES_ARENA_SMALL]    = {RES_BACK_MULTIPOOL, .min_block=4096, .max_block=1u<<24} },
  /* one tuned roster per kind: scenes, fonts, levels, scripts, saves, packs ... */
};
static res_model MODEL_B = {
  .name = "model-b", .root_axis = RES_ROOT_KIND,       // a root HEAP per res_kind
  .arena_by_key = B_ARENAS, .arena_by_key_count = RES_KIND_COUNT,
  .small_max = 256u*1024u, .needs_teardown_records = true,
};
The KIND selects the ROOT (in res_place_plan: site.root = root_index_for_key(plan->kind)), so a kind is a REAL backing domain with its own heap, its own registry shard, its own class histogram -- never "a tag in the Model A pool", which B.4 forbids by name. Whole-kind teardown (subsystem restart) IS a mi_heap_destroy. Its hostile ground -- a level retirement spanning many kinds -- costs a retail walk across every kind root, and the telemetry cube shows the cost per kind.

--- MODEL C: lifetime-major ---
static res_model MODEL_C = {
  .name = "model-c", .root_axis = RES_ROOT_LIFETIME,   // a root HEAP per lifetime domain
  .small_max = SIZE_MAX,                               // one multipool serves the full
  .needs_teardown_records = false,                     // distribution inside each lifetime
  .arena = {
    [RES_ARENA_SMALL]    = { RES_BACK_MULTIPOOL, .min_block=64, .max_block=1u<<24,
                             .direct_landing=true },
    [RES_ARENA_TRANSFER] = { RES_BACK_HEAP, .transferable=true, .direct_landing=true },
  },
};
// route_all(&MODEL_C, RES_ARENA_SMALL); route_role(&MODEL_C, RES_ROLE_TRANSFER, RES_ARENA_TRANSFER);
res_place_domain_winkable(lt) == true for every lifetime: retire is invalidate -> epoch grace -> ONE mi_heap_destroy. Registry shard, names, dep records, payloads and derived objects ALL live in the level's root, so "residual footprint after a cycle" is a real, measurable zero rather than an estimate. Its hostile ground (cross-level sharing, promotion, category iteration) runs through ano_res_promote and SHARED_IMMUTABLE, and every byte of it is charged.

--- MODEL D: role-split ---
static res_model MODEL_D = {
  .name = "model-d", .root_axis = RES_ROOT_ROLE,       // a root HEAP per role class
  .small_max = 256u*1024u, .needs_teardown_records = true,
  .arena = {
    [RES_ARENA_METADATA] = { RES_BACK_MULTIPOOL, .min_block=64,  .max_block=4096 },
    [RES_ARENA_SMALL]    = { RES_BACK_MULTIPOOL, .min_block=256, .max_block=1u<<18,
                             .direct_landing=true },
    [RES_ARENA_BULK]     = { RES_BACK_HEAP, .direct_landing=true },
    [RES_ARENA_CHUNK]    = { RES_BACK_POOL, .block_size=RMOS_CHUNK_MAX, .max_blocks=8 },
    [RES_ARENA_PLANE]    = { RES_BACK_STRIPE, .grain=ANO_THREAD_LINE },
    [RES_ARENA_STAGING]  = { RES_BACK_MONOTONIC, .first_slab=1u<<20 },
    [RES_ARENA_TRANSFER] = { RES_BACK_HEAP, .transferable=true, .direct_landing=true },
  },
};
// route: REGISTRY/NAME/DEPENDENCY -> METADATA;  PAYLOAD -> SMALL (<= small_max) else BULK;
//        DERIVED + RES_DEST_BULK  -> PLANE;     STAGING -> STAGING;  TRANSFER -> TRANSFER.
Roles are real backing domains. A lifetime SPANS every role root, so res_place_domain_winkable == false and retire touches each role root exactly once via res_site.root -- "every resource records the role domains it spans, and retire/release handles all of them exactly once" (B.6), which res_site gives us for free. That is D's honest wound (multi-domain teardown complexity, bookkeeping overhead, inter-role fragmentation) and it now shows up in retire_ns and in the per-role telemetry axis. Its home ground -- bounded chunk reuse, zero-copy GPU/audio hand-off at ANY size, SoA traversal -- falls out of RES_ARENA_CHUNK / PLANE / TRANSFER actually existing.

--- MODEL E: the full C x D hybrid ---
static const res_arena_spec E_ARENAS[ANO_RES_LIFETIME_COUNT][RES_ARENA_COUNT] = {
  [ANO_RES_LIFETIME_ENGINE] = { /* long-lived tuning */ },
  [ANO_RES_LIFETIME_WORLD_LEVEL] = {
    [RES_ARENA_METADATA] = { RES_BACK_MULTIPOOL, .min_block=64,  .max_block=4096 },
    [RES_ARENA_SMALL]    = { RES_BACK_MULTIPOOL, .min_block=256, .max_block=1u<<18,
                             .direct_landing=true },
    [RES_ARENA_BULK]     = { RES_BACK_HEAP, .direct_landing=true },
    [RES_ARENA_CHUNK]    = { RES_BACK_POOL, .block_size=RMOS_CHUNK_MAX, .max_blocks=8 },
    [RES_ARENA_PLANE]    = { RES_BACK_STRIPE, .grain=ANO_THREAD_LINE },
    [RES_ARENA_STAGING]  = { RES_BACK_MONOTONIC, .first_slab=1u<<20 },
    [RES_ARENA_TRANSFER] = { RES_BACK_HEAP, .transferable=true },  // the process transfer heap
  },
  [ANO_RES_LIFETIME_STREAMING]   = { /* chunk-heavy */ },
  [ANO_RES_LIFETIME_SAVE_CONFIG] = { /* tiny */ },
};
static res_model MODEL_E = {
  .name = "model-e", .root_axis = RES_ROOT_LIFETIME,          // C's root axis
  .arena_by_key = E_ARENAS, .arena_by_key_count = ANO_RES_LIFETIME_COUNT,
  .small_max = 256u*1024u, .needs_teardown_records = false,   // C's wink-out
  /* route == D's role split, INSIDE each lifetime root */
};
E is literally C's root_axis plus D's route plane plus a per-lifetime arena roster. Nothing in the registry knows it exists. Staging winks at ingest end (monotonic reset), the level domain winks at retire (one mi_heap_destroy), transfer blocks live in the process transfer heap and come back through ano_res_transfer_free. E receives no credit for components that do not exist, because every component it names is an arena spec that either has a backing or is RES_BACK_NONE -- and RES_BACK_NONE routes to REFUSE, which fails loudly at plan time.

--- WHY THIS HOSTS ALL FIVE, MECHANICALLY ---
res_place_plan is about 30 lines, and its ONLY model-dependent lines are these:

    uint32_t key = model->root_axis == RES_ROOT_KIND     ? (uint32_t)plan->kind
                 : model->root_axis == RES_ROOT_LIFETIME ? plan->lifetime.owner
                 : model->root_axis == RES_ROOT_ROLE     ? role_class(plan->role)
                 : 0;                                    // RES_ROOT_SINGLE
    int8_t a = model->kind_route[plan->kind][plan->role];          // -1 -> fall through
    if (a < 0) a = (int8_t)model->route[plan->role][plan->destination];
    if (a == RES_ARENA_SMALL && size > model->small_max) a = RES_ARENA_BULK;
    if (a == RES_ARENA_COUNT || spec_of(model, key, a)->backing == RES_BACK_NONE)
        return -1;                                                // refused, loudly
    /* fill site from root[key].arena[a] + the spec: serving, alignment (REFUSE if the arena
       cannot meet plan->alignment -- today the pooled path silently drops it, registry:160-165,
       and a 20-byte payload asking for ANO_CACHE_LINE gets 32-byte alignment from the 32-byte
       class), direct_landing, transferable, winkable = (root_axis == RES_ROOT_LIFETIME) */
    out->cell = res_tel_cell(plan);
    if (model->plan_hook) return model->plan_hook(model, plan, size, out);

Everything else -- the registry, the epoch reclamation, the publication directory, the read scopes, the save protocol, every domain extension, the renderer, the mixer, the VM -- is IDENTICAL across all five. The difference between the models is a root axis, an arena roster and a routing plane: DATA. That is the load-bearing claim, and it is why registry shards, names, metadata, payloads, derived objects and teardown records all land in each model's OWN hierarchy without a single `if (model == ...)` anywhere outside res_place_plan.
